@app.route('/reset-mfa', methods=['GET', 'POST'])
def reset_mfa():
    if request.method == 'POST':
        email = request.form['email']
        user = User.query.filter_by(email=email).first()
        if user:
            token = secrets.token_hex(32)
            message = Message('Account Recovery Link', sender='your_email@example.com', recipients=[email])
            message.body = f'Click this link to reset your MFA settings: {url_for("reset_mfa_confirm", token=token, _external=True)}'
            mail.send(message)
            flash('An email with instructions has been sent to your registered email address.')
            return redirect(url_for('login'))
        else:
            flash('The email address is not registered.')

